-- Trigger function to populate users table from auth.users on signup
CREATE OR REPLACE FUNCTION public.handle_new_user()
RETURNS trigger LANGUAGE plpgsql SECURITY DEFINER SET search_path = public AS $$
BEGIN
  INSERT INTO public.users (id, name, email, phone, avatar, "totalOrders", "joinedDate", created_at, updated_at)
  VALUES (
    NEW.id,
    NEW.raw_user_meta_data ->> 'name',
    NEW.email,
    NEW.raw_user_meta_data ->> 'phone',
    NEW.raw_user_meta_data ->> 'avatar',
    COALESCE((NEW.raw_user_meta_data ->> 'totalOrders')::integer, 0),
    now(),
    now(),
    now()
  )
  ON CONFLICT (id) DO NOTHING;
  RETURN NEW;
END; $$;

DROP TRIGGER IF EXISTS on_auth_user_created ON auth.users;
CREATE TRIGGER on_auth_user_created AFTER INSERT ON auth.users FOR EACH ROW EXECUTE FUNCTION public.handle_new_user();

-- === Deterministic CRUD policies for user-owned tables (generated by SupabaseConfigAgent) ===
-- Every table with a direct or transitive ownership path to auth.users gets INSERT/UPDATE/DELETE
-- policies so client-side writes by the owner succeed while cross-user writes are blocked.
-- Idempotent: safe to re-run.
DROP POLICY IF EXISTS "Users can insert own addresses" ON public."addresses";
CREATE POLICY "Users can insert own addresses" ON public."addresses" FOR INSERT WITH CHECK (auth.uid() = "user_id");
DROP POLICY IF EXISTS "Users can update own addresses" ON public."addresses";
CREATE POLICY "Users can update own addresses" ON public."addresses" FOR UPDATE USING (auth.uid() = "user_id") WITH CHECK (auth.uid() = "user_id");
DROP POLICY IF EXISTS "Users can delete own addresses" ON public."addresses";
CREATE POLICY "Users can delete own addresses" ON public."addresses" FOR DELETE USING (auth.uid() = "user_id");

DROP POLICY IF EXISTS "Users can insert own payment_methods" ON public."payment_methods";
CREATE POLICY "Users can insert own payment_methods" ON public."payment_methods" FOR INSERT WITH CHECK (auth.uid() = "user_id");
DROP POLICY IF EXISTS "Users can update own payment_methods" ON public."payment_methods";
CREATE POLICY "Users can update own payment_methods" ON public."payment_methods" FOR UPDATE USING (auth.uid() = "user_id") WITH CHECK (auth.uid() = "user_id");
DROP POLICY IF EXISTS "Users can delete own payment_methods" ON public."payment_methods";
CREATE POLICY "Users can delete own payment_methods" ON public."payment_methods" FOR DELETE USING (auth.uid() = "user_id");

