DROP POLICY IF EXISTS "Users can update own user_preferences" ON public."user_preferences";
CREATE POLICY "Users can update own user_preferences" ON public."user_preferences" FOR UPDATE USING (auth.uid() = "user_id") WITH CHECK (auth.uid() = "user_id");
DROP POLICY IF EXISTS "Users can delete own user_preferences" ON public."user_preferences";
CREATE POLICY "Users can delete own user_preferences" ON public."user_preferences" FOR DELETE USING (auth.uid() = "user_id");

DROP POLICY IF EXISTS "Users can insert own orders" ON public."orders";
CREATE POLICY "Users can insert own orders" ON public."orders" FOR INSERT WITH CHECK (auth.uid() = "userId");
DROP POLICY IF EXISTS "Users can update own orders" ON public."orders";
CREATE POLICY "Users can update own orders" ON public."orders" FOR UPDATE USING (auth.uid() = "userId") WITH CHECK (auth.uid() = "userId");
DROP POLICY IF EXISTS "Users can delete own orders" ON public."orders";
CREATE POLICY "Users can delete own orders" ON public."orders" FOR DELETE USING (auth.uid() = "userId");

DROP POLICY IF EXISTS "Users can insert own order_items" ON public."order_items";
CREATE POLICY "Users can insert own order_items" ON public."order_items" FOR INSERT WITH CHECK ("order_id" IN (SELECT "id" FROM public."orders" WHERE "userId" = auth.uid()));
DROP POLICY IF EXISTS "Users can update own order_items" ON public."order_items";
CREATE POLICY "Users can update own order_items" ON public."order_items" FOR UPDATE USING ("order_id" IN (SELECT "id" FROM public."orders" WHERE "userId" = auth.uid())) WITH CHECK ("order_id" IN (SELECT "id" FROM public."orders" WHERE "userId" = auth.uid()));
DROP POLICY IF EXISTS "Users can delete own order_items" ON public."order_items";
CREATE POLICY "Users can delete own order_items" ON public."order_items" FOR DELETE USING ("order_id" IN (SELECT "id" FROM public."orders" WHERE "userId" = auth.uid()));

DROP POLICY IF EXISTS "Users can insert own favorites" ON public."favorites";
CREATE POLICY "Users can insert own favorites" ON public."favorites" FOR INSERT WITH CHECK (auth.uid() = "user_id");
DROP POLICY IF EXISTS "Users can update own favorites" ON public."favorites";
