DROP POLICY IF EXISTS "restaurant-images_owner_delete" ON storage.objects;
CREATE POLICY "restaurant-images_owner_delete" ON storage.objects FOR DELETE TO authenticated USING (bucket_id = 'restaurant-images' AND (storage.foldername(name))[1] = auth.uid()::text);

